1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life — nextGeneration", () => {
5	  it("should return [] for empty input — empty grid stays empty", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	
9	  it("should kill a lone live cell — nextGeneration([[0,0]]) returns []", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	
13	  it("should kill two adjacent live cells (underpopulation) — nextGeneration([[0,1],[1,1]]) returns []", () => {
14	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
15	  });
16	
17	  it("should leave a 2x2 block unchanged (still life) — nextGeneration([[0,0],[1,0],[0,1],[1,1]]) returns the same four cells", () => {
18	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
19	    const sorted = [...result].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
20	    expect(sorted).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]]);
21	  });
22	
23	  it("should birth the diagonal-completing cell from an L-shape (reproduction) — nextGeneration([[0,0],[1,0],[0,1]]) returns the 2x2 block [[0,0],[1,0],[0,1],[1,1]]", () => {
24	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
25	    const sorted = [...result].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
26	    expect(sorted).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]]);
27	  });
28	
29	  it.todo(
30	    "should kill the center of a full 3x3 from overpopulation — center (1,1) is absent from nextGeneration of all nine cells of the 3x3"
31	  );
32	
33	  it.todo(
34	    "should oscillate a vertical blinker into a horizontal blinker — nextGeneration([[0,0],[0,1],[0,2]]) returns [[-1,1],[0,1],[1,1]]"
35	  );
36	});
