1	export type Cell = [number, number];
2	
3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const survives = (count: number, wasAlive: boolean): boolean =>
6	  wasAlive ? count === 2 || count === 3 : count === 3;
7	
8	export function nextGeneration(cells: Cell[]): Cell[] {
9	  const alive = new Set(cells.map(cellKey));
10	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
11	
12	  for (const [x, y] of cells) {
13	    for (let dx = -1; dx <= 1; dx++) {
14	      for (let dy = -1; dy <= 1; dy++) {
15	        if (dx === 0 && dy === 0) continue;
16	        const neighbor: Cell = [x + dx, y + dy];
17	        const k = cellKey(neighbor);
18	        const entry = neighborCounts.get(k);
19	        if (entry) entry.count++;
20	        else neighborCounts.set(k, { cell: neighbor, count: 1 });
21	      }
22	    }
23	  }
24	
25	  const next: Cell[] = [];
26	  for (const [k, { cell, count }] of neighborCounts) {
27	    if (survives(count, alive.has(k))) next.push(cell);
28	  }
29	  return next;
30	}
