it("should kill the center of a full 3x3 from overpopulation — center (1,1) is absent from nextGeneration of all nine cells of the 3x3", () => {
  const result = nextGeneration([
    [0, 0], [1, 0], [2, 0],
    [0, 1], [1, 1], [2, 1],
    [0, 2], [1, 2], [2, 2],
  ]);
  expect(result).not.toContainEqual([1, 1]);
});
